func concernToMD(p *Concern, depth int) string {
	indent := strings.Repeat("  ", depth)
	md := fmt.Sprintf("%s- **%s**\n", p.GetIDAirbus()+indent, p.Name)
	if p.Description != "" {
		md += fmt.Sprintf("%s  - Description: %s\n", indent, p.Description)
	}
	if len(p.SubConcerns) > 0 {
		md += fmt.Sprintf("%s  - SubConcerns:\n", indent)
		for _, sub := range p.SubConcerns {
			md += concernToMD(sub, depth+2)
		}
	}
	return md
}

func noteToMD(n *Note, depth int) string {
	indent := strings.Repeat("  ", depth)
	md := fmt.Sprintf("%s- **%s**\n", indent, n.Name)
	return md
}
